(function() {
  const mapPage = document.getElementById('qyTourMapPage');
  const vrPage = document.getElementById('qyVRPage');
  const title = document.getElementById('qyVRTitle');
  const defaultPanorama = 'data:image/jpeg;base64,';

  let viewer = null;
  let rotating = true;


  const qyNarratorText = "来济南如果没在泉城广场看场喷泉，那这趟旅行基本等于白来。\n这里不只是地理意义上的City Center，更是年轻人Citywalk的灵魂坐标。\n广场中央那座蓝色巨型雕塑叫泉，是济南的超级Icon，拍极简风大片和潮流街拍都很出片。\n莲花音乐喷泉更是必打卡项，音乐响起，水柱随着节奏起舞，配合夜晚灯光秀，氛围感直接拉满。\n傍晚在这儿，你能看到滑板少年、街舞社团，还有浪漫日落。\n建议下午五点左右出发，先拍蓝色雕塑，晚上看完喷泉，再顺路去恒隆或者宽厚里吃火锅，这趟行程真的很顺滑。";
  const qyNarratorSubtitles = ["来济南如果没在泉城广场看场喷泉，那这趟旅行基本等于白来。", "这里不只是 City Center，更是年轻人 Citywalk 的灵魂坐标。", "中央蓝色巨型雕塑“泉”，就是济南的超级 Icon。", "想拍极简风大片，或者潮流街拍，背景选它准没错。", "莲花音乐喷泉是必打卡项，音乐一响，水柱跟着节奏起舞。", "夜晚灯光秀一开，视觉冲击力直戳审美点，氛围感拉满。", "傍晚还能看到滑板少年、街舞社团和超浪漫日落。", "建议下午五点来，拍完日落看喷泉，再去宽厚里炫火锅。"];
  let qyNarratorSubtitleTimer = null;
  let qyNarratorProgressTimer = null;

  function qyStopNarrator() {
    if (typeof speechSynthesis !== 'undefined') speechSynthesis.cancel();
    clearInterval(qyNarratorSubtitleTimer);
    clearInterval(qyNarratorProgressTimer);
    const narrator = document.getElementById('qyNarrator');
    const progress = document.getElementById('qyNarratorProgress');
    if (narrator) narrator.classList.remove('qy-speaking');
    if (progress) progress.style.width = '0%';
  }

  function qySetNarratorForPlace(name) {
    const narrator = document.getElementById('qyNarrator');
    const subtitle = document.getElementById('qyNarratorSubtitle');
    if (!narrator) return;
    const shouldShow = String(name || '').indexOf('泉城广场') !== -1;
    narrator.classList.toggle('qy-show', shouldShow);
    if (!shouldShow) qyStopNarrator();
    if (subtitle) subtitle.textContent = qyNarratorSubtitles[0];
  }

  function qyStartNarratorSpeech() {
    const narrator = document.getElementById('qyNarrator');
    const subtitle = document.getElementById('qyNarratorSubtitle');
    const progress = document.getElementById('qyNarratorProgress');
    if (!narrator || !subtitle || !progress || typeof SpeechSynthesisUtterance === 'undefined') return;

    qyStopNarrator();
    narrator.classList.add('qy-speaking');
    progress.style.width = '0%';

    const utter = new SpeechSynthesisUtterance(qyNarratorText);
    utter.lang = 'zh-CN';
    utter.rate = 1.03;
    utter.pitch = 1.04;
    const voices = speechSynthesis.getVoices();
    const zhVoice = voices.find(v => v.lang && v.lang.toLowerCase().includes('zh'));
    if (zhVoice) utter.voice = zhVoice;
    speechSynthesis.speak(utter);

    let index = 0;
    subtitle.textContent = qyNarratorSubtitles[index];
    qyNarratorSubtitleTimer = setInterval(function() {
      index += 1;
      if (index >= qyNarratorSubtitles.length) {
        clearInterval(qyNarratorSubtitleTimer);
        return;
      }
      subtitle.textContent = qyNarratorSubtitles[index];
    }, 3750);

    const start = Date.now();
    const duration = 30000;
    qyNarratorProgressTimer = setInterval(function() {
      const pct = Math.min(100, ((Date.now() - start) / duration) * 100);
      progress.style.width = pct + '%';
      if (pct >= 100) {
        clearInterval(qyNarratorProgressTimer);
        narrator.classList.remove('qy-speaking');
      }
    }, 100);

    utter.onend = function() {
      narrator.classList.remove('qy-speaking');
      progress.style.width = '100%';
      clearInterval(qyNarratorSubtitleTimer);
      clearInterval(qyNarratorProgressTimer);
    };
  }

  const qyNarratorStartBtn = document.getElementById('qyNarratorStart');
  if (qyNarratorStartBtn) qyNarratorStartBtn.addEventListener('click', qyStartNarratorSpeech);
  if (typeof speechSynthesis !== 'undefined') {
    speechSynthesis.onvoiceschanged = function() { speechSynthesis.getVoices(); };
  }

  function hideFrontScroll() {
    document.body.style.overflow = 'hidden';
  }

  function restoreFrontScroll() {
    document.body.style.overflow = '';
  }

  function centerMap() {
    const scroller = document.getElementById('qyMapScroll');
    if (scroller) {
      scroller.scrollLeft = Math.max(0, (scroller.scrollWidth - scroller.clientWidth) / 2);
    }
  }

  function openMapPage() {
    mapPage.classList.add('qy-active');
    vrPage.classList.remove('qy-active');
    document.body.classList.remove('qy-vr-open');
    document.body.classList.remove('qc-quancheng-vr');
    hideFrontScroll();
    destroyViewer();
    setTimeout(centerMap, 60);
  }

  function closeMapPage() {
    mapPage.classList.remove('qy-active');
    vrPage.classList.remove('qy-active');
    document.body.classList.remove('qy-vr-open');
    document.body.classList.remove('qc-quancheng-vr');
    restoreFrontScroll();
    qyStopNarrator();
    destroyViewer();
  }

  function destroyViewer() {
    if (viewer) {
      try { viewer.destroy(); } catch(e) {}
      viewer = null;
    }
    const pano = document.getElementById('qyPanorama');
    if (pano) pano.innerHTML = '';
  }

  function createViewer(imgUrl) {
    destroyViewer();

    const pano = document.getElementById('qyPanorama');
    const inner = document.createElement('div');
    inner.id = 'qyPanoramaInner_' + Date.now();
    inner.style.width = '100%';
    inner.style.height = '100%';
    pano.appendChild(inner);

    viewer = pannellum.viewer(inner.id, {
      type: 'equirectangular',
      panorama: imgUrl,
      autoLoad: true,
      autoRotate: -2,
      compass: true,
      showControls: true,
      hfov: 105,
      minHfov: 40,
      maxHfov: 140
    });

    rotating = true;
    document.getElementById('qyRotate').textContent = '自动旋转';
    setTimeout(function() {
      try { viewer.resize(); } catch(e) {}
    }, 450);
  }

  function openVR(name, imgUrl) {
    mapPage.classList.remove('qy-active');
    vrPage.classList.add('qy-active');
    document.body.classList.add('qy-vr-open');
    document.body.classList.toggle('qc-quancheng-vr', String(name || '').indexOf('泉城广场') !== -1);
    hideFrontScroll();

    title.textContent = (name || '720° VR 全景') + ' · 720° VR 全景';
    qySetNarratorForPlace(name);

    // 只请求系统横屏，不旋转DOM，避免竖屏黑屏/无法进入
    if (screen.orientation && screen.orientation.lock) {
      screen.orientation.lock('landscape').catch(function(){});
    }

    setTimeout(function() {
      createViewer(imgUrl || defaultPanorama);
    }, 120);
  }

  function backToMap() {
    vrPage.classList.remove('qy-active');
    document.body.classList.remove('qy-vr-open');
    document.body.classList.remove('qc-quancheng-vr');
    qyStopNarrator();
    openShandongGuide();
  }

  window.openQYTourMap = openMapPage;
  window.openQYVR = openVR;

  document.getElementById('qyBackHome').addEventListener('click', closeMapPage);
  document.getElementById('qyBackMap').addEventListener('click', backToMap);
  document.getElementById('qyOpenFirstVR').addEventListener('click', function() {
    openVR('泉城广场');
  });

  document.querySelectorAll('.qy-hotspot').forEach(function(btn) {
    btn.addEventListener('click', function(e) {
      e.preventDefault();
      e.stopPropagation();
      openVR(btn.dataset.name || btn.textContent.trim());
    });
  });

  document.getElementById('qyZoomIn').addEventListener('click', function() {
    if (viewer) viewer.setHfov(Math.max(40, viewer.getHfov() - 10));
  });

  document.getElementById('qyZoomOut').addEventListener('click', function() {
    if (viewer) viewer.setHfov(Math.min(140, viewer.getHfov() + 10));
  });

  document.getElementById('qyRotate').addEventListener('click', function() {
    if (!viewer) return;
    if (rotating) {
      viewer.stopAutoRotate();
      this.textContent = '开始旋转';
    } else {
      viewer.startAutoRotate(-2);
      this.textContent = '自动旋转';
    }
    rotating = !rotating;
  });

  document.getElementById('qyFullScreen').addEventListener('click', function() {
    if (viewer) viewer.toggleFullscreen();
  });

  document.getElementById('qyUpload').addEventListener('change', function(e) {
    const file = e.target.files && e.target.files[0];
    if (!file) return;
    const reader = new FileReader();
    reader.onload = function(evt) {
      createViewer(evt.target.result);
    };
    reader.readAsDataURL(file);
  });

  document.addEventListener('keydown', function(e) {
    if (e.key === 'Escape') {
      if (vrPage.classList.contains('qy-active')) backToMap();
      else if (mapPage.classList.contains('qy-active')) closeMapPage();
    }
  });

  window.addEventListener('resize', function() {
    if (mapPage.classList.contains('qy-active')) setTimeout(centerMap, 120);
    if (viewer) setTimeout(function() { try { viewer.resize(); } catch(e) {} }, 150);
  });

  // 桌面鼠标拖拽横向滑动；手机使用原生触摸横滑
  (function enableDragScroll() {
    const scroller = document.getElementById('qyMapScroll');
    let down = false;
    let startX = 0;
    let startScroll = 0;

    scroller.addEventListener('mousedown', function(e) {
      down = true;
      startX = e.pageX;
      startScroll = scroller.scrollLeft;
    });

    window.addEventListener('mouseup', function() {
      down = false;
    });

    scroller.addEventListener('mousemove', function(e) {
      if (!down) return;
      e.preventDefault();
      scroller.scrollLeft = startScroll - (e.pageX - startX);
    });
  })();

  function bindMoreEntry() {
    document.querySelectorAll('.tool-item, button, a, [role="button"], .menu-item, .nav-item, .card').forEach(function(el) {
      const text = (el.innerText || el.textContent || '').replace(/\s+/g, '').trim();
      const label = el.querySelector && el.querySelector('.tool-label');
      const labelText = label ? label.textContent.trim() : '';
      if (text === '更多' || labelText === '更多' || text.endsWith('更多')) {
        el.style.cursor = 'pointer';
        if (!el.dataset.qyMoreBound) {
          el.dataset.qyMoreBound = '1';
          el.addEventListener('click', function(ev) {
            ev.preventDefault();
            ev.stopPropagation();
            openShandongGuide();
          }, true);
        }
      }
    });
  }

  document.addEventListener('click', function(e) {
    if (mapPage.classList.contains('qy-active') || vrPage.classList.contains('qy-active')) return;

    const entry = e.target.closest && e.target.closest('.tool-item, button, a, [role="button"], .menu-item, .nav-item, .card');
    if (!entry) return;

    const text = (entry.innerText || entry.textContent || '').replace(/\s+/g, '').trim();
    const label = entry.querySelector && entry.querySelector('.tool-label');
    const labelText = label ? label.textContent.trim() : '';

    if (text === '更多' || labelText === '更多' || text.endsWith('更多')) {
      e.preventDefault();
      e.stopPropagation();
      openShandongGuide();
    }
  }, true);

  if (document.readyState === 'loading') {
    document.addEventListener('DOMContentLoaded', bindMoreEntry);
  } else {
    bindMoreEntry();
  }
  setTimeout(bindMoreEntry, 500);
  setTimeout(bindMoreEntry, 1500);
})();
